package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.Excluder;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class GsonTest {

  private Gson gson;
  private Excluder excluderMock;

  @BeforeEach
  public void setUp() throws Exception {
    excluderMock = mock(Excluder.class);
    gson = new Gson();

    // Use reflection to set the private final excluder field to the mock
    Field excluderField = Gson.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    excluderField.set(gson, excluderMock);
  }

  @Test
  public void testExcluder_returnsExcluderInstance() {
    Excluder result = gson.excluder();
    assertNotNull(result);
    assertSame(excluderMock, result);
  }
}
